1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using TicketClassifier.Models;
4. 
5. namespace TicketClassifier.Services;
6. 
7. public class ModelTrainingService
8. {
9.     private readonly MLContext _mlContext;
10.     private readonly ILogger<ModelTrainingService> _logger;
11.     private readonly string _dataPath;
12.     private readonly string _modelPath;
13. 
14.     public ModelTrainingService(ILogger<ModelTrainingService> logger)
15.     {
16.         _mlContext = new MLContext(seed: 42);
17.         _logger = logger;
18.         _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
19.         _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
20.     }
21. 
22.     public (ITransformer Model, EvaluationMetrics Metrics) TrainAndEvaluate()
23.     {
24.         _logger.LogInformation("Loading training data from {Path}", _dataPath);
25.         var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
26.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
27. 
28.         var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
29. 
30.         var pipeline = _mlContext.Transforms.Text
31.             .FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
32.             .Append(_mlContext.Transforms.Text
33.                 .FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
34.             .Append(_mlContext.Transforms.Concatenate("Features",
35.                 "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
36.             .Append(_mlContext.Transforms.Conversion
37.                 .MapValueToKey("Label", nameof(TicketInput.Category)))
38.             .Append(_mlContext.MulticlassClassification.Trainers
39.                 .SdcaMaximumEntropy("Label", "Features"))
40.             .Append(_mlContext.Transforms.Conversion
41.                 .MapKeyToValue("PredictedLabel"));
42. 
43.         _logger.LogInformation("Training model...");
44.         var model = pipeline.Fit(split.TrainSet);
45. 
46.         _logger.LogInformation("Evaluating model...");
47.         var predictions = model.Transform(split.TestSet);
48.         var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);
49. 
50.         _logger.LogInformation(
51.             "Model metrics — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}, LogLossReduction: {Reduction:F4}",
52.             metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss, metrics.LogLossReduction);
53. 
54.         var confusionMatrix = metrics.ConfusionMatrix;
55.         var perClass = new Dictionary<string, PerClassMetrics>();
56. 
