using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ObjectPool<PredictionEngine<TicketInput, TicketPrediction>> _predictionPool;
    private ITransformer? _model;
    private DataViewSchema? _schema;

    public ModelTrainingService(ILogger<ModelTrainingService> logger)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
        _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _predictionPool = new ObjectPool<PredictionEngine<TicketInput, TicketPrediction>>(
            () => _mlContext.Model.CreatePredictionEngine<TicketInput, TicketPrediction>(_model));
    }

    public (ITransformer Model, EvaluationMetrics Metrics) TrainAndEvaluate()
    {
        _logger.LogInformation("Loading training data from {Path}", _dataPath);
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text
            .FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);
        _model = model;
        _schema = split.TrainSet.Schema;

        _logger.LogInformation("Evaluating model...");
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation(
            "Model metrics — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}, LogLossReduction: {Reduction:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss, metrics.LogLossReduction);

        var confusionMatrix = metrics.ConfusionMatrix;
        var perClass = new Dictionary<string, PerClassMetrics>();

        var schema = predictions.Schema;
        var labelColumn = schema.GetColumnOrNull("Label");
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        if (labelColumn.HasValue)
        {
            labelColumn.Value.GetKeyValues(ref slotNames);
        }
        var classNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        for (int i = 0; i < classNames.Length && i < confusionMatrix.PerClassPrecision.Count; i++)
        {
            perClass[classNames[i]] = new PerClassMetrics
            {
                Precision = confusionMatrix.PerClassPrecision[i],
                Recall = confusionMatrix.PerClassRecall[i],
            };
            _logger.LogInformation("  {Class}: Precision={Precision:F4}, Recall={Recall:F4}",
                classNames[i], confusionMatrix.PerClassPrecision[i], confusionMatrix.PerClassRecall[i]);
        }

        _mlContext.Model.Save(model, _schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return (model, new EvaluationMetrics
        {
            MicroAccuracy = (float)metrics.MicroAccuracy,
            MacroAccuracy = (float)metrics.MacroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
            PerClass = perClass,
        });
    }

    /// <summary>Thread-safe prediction using a pooled PredictionEngine.</summary>
    public TicketPrediction Predict(TicketInput input)
    {
        if (_model is null)
            throw new InvalidOperationException("Model has not been trained. Call TrainAndEvaluate first.");

        var engine = _predictionPool.Get();
        try
        {
            return engine.Predict(input);
        }
        finally
        {
            _predictionPool.Return(engine);
        }
    }

    public string ModelPath => _modelPath;
}

/// <summary>Simple thread-safe object pool.</summary>
file sealed class ObjectPool<T> where T : class
{
    private readonly Func<T> _factory;
    private readonly ConcurrentBag<T> _objects = new();

    public ObjectPool(Func<T> factory) => _factory = factory;
    public T Get() => _objects.TryTake(out var item) ? item : _factory();
    public void Return(T item) => _objects.Add(item);
}

